// And groups predicates with the AND operator between them.
func And(predicates ...predicate.NoteConnectionJob) predicate.NoteConnectionJob {
	return predicate.NoteConnectionJob(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.NoteConnectionJob) predicate.NoteConnectionJob {
	return predicate.NoteConnectionJob(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.NoteConnectionJob) predicate.NoteConnectionJob {
	return predicate.NoteConnectionJob(sql.NotPredicates(p))
}
